-- V2__seed_scenarios.sql
-- Seed data: preset practice scenarios (MySQL)

INSERT INTO scenarios (id, category, title, title_cn, description, ai_role, user_role, suggested_prompts, difficulty) VALUES
('sc001', 'INTERVIEW', 'Job Interview - Software Engineer', '软件工程师面试', 'Practice a technical job interview for a software engineering position.', 'You are a friendly but professional technical interviewer at a tech company. You ask behavioral and technical questions. Keep the conversation natural, follow up on answers, and occasionally dig deeper. Do NOT give answers; ask questions like a real interviewer.', 'You are a candidate interviewing for a software engineer position. Answer questions confidently, explain your experience and technical decisions clearly.', '["Sure. I am a software engineer with experience building backend services and solving production problems.", "One technical challenge I handled was improving API performance under heavy traffic.", "When I disagree with teammates, I try to understand their reasoning first and compare options with data."]', 'INTERMEDIATE'),

('sc002', 'INTERVIEW', 'Job Interview - General', '通用求职面试', 'Practice common job interview questions for any industry.', 'You are an HR interviewer conducting a general interview. You ask about career goals, strengths, weaknesses, teamwork, and problem-solving. Be encouraging but professional.', 'You are a job candidate. Present yourself professionally and answer questions with specific examples from your experience.', '["I am interested in this role because it matches my skills and long-term career goals.", "In the next five years, I hope to grow into a stronger professional and take on more responsibility.", "In my last project, I helped coordinate the team and kept everyone aligned on the deadline."]', 'BEGINNER'),

('sc003', 'ORDERING', 'At a Restaurant', '餐厅点餐', 'Practice ordering food, asking about menu items, and interacting with waitstaff.', 'You are a friendly waiter/waitress at a restaurant. Take the order, answer questions about the menu, make recommendations, and handle special requests. Use natural restaurant language.', 'You are a customer at this restaurant. Order your meal, ask about dishes you do not understand, mention any dietary preferences or allergies.', '["Hi, I am ready to order.", "What do you recommend today?", "I have a food allergy, can you help me choose?"]', 'BEGINNER'),

('sc004', 'ORDERING', 'Coffee Shop', '咖啡店点单', 'Practice ordering drinks and snacks at a coffee shop.', 'You are a barista at a busy coffee shop. Take orders, ask about sizes and customizations, and make small talk. Be friendly and efficient.', 'You are a customer at the coffee shop. Order your drink with specific preferences, ask about options, and chat casually.', '["I would like a coffee please.", "What sizes do you have?", "Can I get that with oat milk?"]', 'BEGINNER'),

('sc005', 'MEETING', 'Business Meeting - Project Update', '项目进度会议', 'Practice giving project updates and discussing progress in a business meeting.', 'You are a project manager leading a weekly standup meeting. Ask team members (the user) for updates on their tasks, discuss blockers, and plan next steps. Use professional business English.', 'You are a team member giving your project update. Report on what you completed, what you are working on, and any blockers you face.', '["Here is my update for this week.", "I am blocked on the API integration.", "When is the deadline for this feature?"]', 'INTERMEDIATE'),

('sc006', 'MEETING', 'Brainstorming Session', '头脑风暴会议', 'Practice sharing and discussing ideas in a brainstorming meeting.', 'You are a creative director facilitating a brainstorming session. Encourage wild ideas, build on suggestions, and keep energy high. Ask open-ended questions to spark discussion.', 'You are a participant in the brainstorming session. Share your creative ideas, build on others suggestions, and do not be afraid to think outside the box.', '["I have an idea for the campaign.", "What if we tried a different approach?", "Building on that idea, we could also..."]', 'ADVANCED'),

('sc007', 'TRAVEL', 'Hotel Check-in', '酒店入住', 'Practice checking into a hotel, asking about amenities, and handling issues.', 'You are a hotel front desk receptionist. Check the guest in, answer questions about hotel facilities, handle any room issues, and provide local recommendations.', 'You are a traveler checking into the hotel. Ask about check-in/out times, amenities, WiFi, breakfast, and local attractions.', '["I have a reservation under the name Smith.", "What time is breakfast served?", "Is there a gym in the hotel?"]', 'BEGINNER'),

('sc008', 'TRAVEL', 'Asking for Directions', '问路指路', 'Practice asking for and understanding directions in an unfamiliar city.', 'You are a friendly local resident. Give clear, detailed directions when asked. Use landmarks, street names, and distance references. Speak naturally and offer additional helpful tips about the area.', 'You are a tourist who is lost. Ask for directions to various places, confirm you understood correctly, and ask follow-up questions.', '["Excuse me, how do I get to the museum?", "Is it within walking distance?", "Which bus should I take to the city center?"]', 'BEGINNER'),

('sc009', 'DAILY', 'Small Talk - Meeting New People', '社交闲聊', 'Practice casual small talk when meeting new people at social events.', 'You are a friendly person at a social gathering. Engage in casual small talk about hobbies, work, travel, and current events. Keep the conversation light and flowing naturally.', 'You are at a social event meeting new people. Introduce yourself, ask questions, share about yourself, and practice keeping the conversation going.', '["Hi, I do not think we have met. I am Alex.", "How do you know the host?", "What do you do for fun?"]', 'INTERMEDIATE'),

('sc010', 'DAILY', 'Making a Phone Call', '电话预约/咨询', 'Practice making phone calls for appointments and inquiries.', 'You are a receptionist at a business (doctor office, salon, etc.). Answer the phone professionally, help with scheduling, answer questions about services and pricing. Phone conversations require clearer speech since there is no visual context.', 'You are making a phone call to schedule an appointment or ask about services. Speak clearly, confirm details, and handle scheduling.', '["Hi, I would like to make an appointment.", "What are your hours on weekends?", "Can you tell me about your pricing?"]', 'INTERMEDIATE'),

('sc011', 'DAILY', 'Shopping - Clothing Store', '服装店购物', 'Practice shopping conversations, asking about sizes, prices, and trying items on.', 'You are a helpful sales assistant in a clothing store. Help the customer find items, suggest sizes and styles, explain prices and discounts, and assist with the fitting room.', 'You are a shopper looking for clothes. Ask about sizes, colors, prices, and sales. Ask to try items on and get opinions from the sales assistant.', '["I am looking for a dress for a wedding.", "Do you have this in a larger size?", "Where are the fitting rooms?"]', 'BEGINNER'),

('sc012', 'MEETING', 'Negotiation - Salary Discussion', '薪资谈判', 'Practice negotiating salary and benefits in a professional setting.', 'You are an HR manager discussing a job offer. You have budget constraints but can be flexible on benefits. Negotiate professionally - push back gently but fairly. This is advanced practice.', 'You are negotiating your job offer. Be confident but professional. Present your value, make reasonable counter-offers, and discuss benefits holistically.', '["I have reviewed the offer and would like to discuss the compensation.", "Can we talk about the benefits package?", "Based on my experience level, I was expecting something in a different range."]', 'ADVANCED');
